/**
 * Variables that recur across flows. Spread into a flow's `variables` map to
 * pick up the shared value. Keeping them in one place ensures every flow
 * uses the same wording — particularly important for per-target divergences
 * where claude/cursor and codex want different phrasings of the same idea.
 *
 * Usage:
 *
 *   variables: {
 *     ...SHARED_VARIABLES,
 *     flowSpecificVar: "...",
 *   }
 *
 * Add a new entry here when the same Targetable string would be defined
 * verbatim in two or more flows. Don't add per-flow content here.
 */
export const SHARED_VARIABLES = {
    /**
     * Connector phrase used when describing instrumentation that races (or
     * sequentially writes, on codex) work in another file. Grammatically
     * expects a continuation: "writes them {{parallelism}} the X edits."
     */
    parallelism: {
        default: "in parallel with",
        codex: "in the same cycle as",
    },
    /**
     * Adverbial phrase used in tabular or bullet contexts where the
     * surrounding grammar doesn't carry over. "(... {{togetherness}} per
     * workflow)".
     */
    togetherness: {
        default: "in parallel",
        codex: "together",
    },
    /**
     * The SDK detection regex set used to find existing instrumented trace
     * functions. Update in lockstep when adding a new SDK language.
     */
    sdkPatterns: '`getFunction("key")`, `get_function("key")`, `bitfab_function "key"`, `WithFunctionName("key")`',
};
